DROP TABLE IF EXISTS zz_checkin_family_member;
DROP TABLE IF EXISTS zz_checkin_application;

CREATE TABLE zz_checkin_application (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  elder_name VARCHAR(32) NOT NULL COMMENT '老人姓名',
  id_card VARCHAR(18) NOT NULL COMMENT '老人身份证号',
  birth_date DATETIME DEFAULT NULL COMMENT '出生日期',
  age INT DEFAULT NULL COMMENT '年龄',
  gender VARCHAR(8) DEFAULT NULL COMMENT '性别',
  contact_phone VARCHAR(16) NOT NULL COMMENT '联系方式',
  home_address VARCHAR(100) NOT NULL COMMENT '家庭住址',
  profile_photo_name VARCHAR(128) NOT NULL COMMENT '一寸照片文件名',
  profile_photo_url VARCHAR(255) DEFAULT NULL COMMENT '一寸照片URL',
  id_card_front_name VARCHAR(128) NOT NULL COMMENT '身份证人像面文件名',
  id_card_front_url VARCHAR(255) DEFAULT NULL COMMENT '身份证人像面URL',
  id_card_back_name VARCHAR(128) NOT NULL COMMENT '身份证国徽面文件名',
  id_card_back_url VARCHAR(255) DEFAULT NULL COMMENT '身份证国徽面URL',
  room_no VARCHAR(32) NOT NULL COMMENT '入住床位',
  care_level VARCHAR(32) NOT NULL COMMENT '护理等级',
  checkin_start_date DATETIME NOT NULL COMMENT '入住开始日期',
  checkin_end_date DATETIME NOT NULL COMMENT '入住结束日期',
  nursing_fee DECIMAL(10,2) NOT NULL DEFAULT 0 COMMENT '护理费用',
  bed_fee DECIMAL(10,2) NOT NULL DEFAULT 0 COMMENT '床位费用',
  other_fee DECIMAL(10,2) NOT NULL DEFAULT 0 COMMENT '其他费用',
  medical_fee DECIMAL(10,2) NOT NULL DEFAULT 0 COMMENT '医保费用',
  subsidy_fee DECIMAL(10,2) NOT NULL DEFAULT 0 COMMENT '政府补贴',
  deposit DECIMAL(10,2) NOT NULL DEFAULT 3000 COMMENT '押金',
  contract_name VARCHAR(64) NOT NULL COMMENT '合同名称',
  sign_date DATETIME NOT NULL COMMENT '签约日期',
  payer_name VARCHAR(32) DEFAULT '' COMMENT '丙方姓名',
  payer_contact VARCHAR(16) DEFAULT '' COMMENT '丙方联系方式',
  contract_file_name VARCHAR(255) NOT NULL COMMENT '入住合同文件名',
  contract_file_url VARCHAR(255) DEFAULT NULL COMMENT '入住合同URL',
  monthly_amount DECIMAL(10,2) NOT NULL DEFAULT 0 COMMENT '每月应付',
  current_amount DECIMAL(10,2) NOT NULL DEFAULT 0 COMMENT '本期应付',
  bill_amount DECIMAL(10,2) NOT NULL DEFAULT 0 COMMENT '账单金额',
  bill_days INT NOT NULL DEFAULT 30 COMMENT '共计天数',
  is_retired TINYINT NOT NULL DEFAULT 0 COMMENT '是否退住:0未退住 1已退住',
  is_deleted TINYINT NOT NULL DEFAULT 0 COMMENT '逻辑删除',
  created_time DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  updated_time DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (id),
  KEY idx_checkin_name (elder_name),
  KEY idx_checkin_idcard (id_card)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='入住申请表';

CREATE TABLE zz_checkin_family_member (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  application_id BIGINT UNSIGNED NOT NULL COMMENT '入住申请ID',
  family_name VARCHAR(32) NOT NULL COMMENT '家属姓名',
  family_contact VARCHAR(16) NOT NULL COMMENT '家属联系方式',
  relation_type VARCHAR(16) NOT NULL COMMENT '与老人关系',
  is_deleted TINYINT NOT NULL DEFAULT 0 COMMENT '逻辑删除',
  PRIMARY KEY (id),
  KEY idx_family_application (application_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='入住家属信息表';


